import{z as t}from"zod";export const ConfirmedSlotEntrySchema=t.object({id:t.string().min(1),name:t.string(),description:t.string(),roleType:t.string().default(""),gender:t.string().default(""),botType:t.string().default("MID_JOURNEY"),theme:t.string().default(""),style:t.string().default(""),imageUrl:t.string().url(),imagePrompt:t.string().default(""),confirmedAt:t.string()}),CharacterImageBindingSchema=t.object({slotEntryId:t.string(),imageUrl:t.string().url(),characterName:t.string(),characterFilename:t.string(),boundAt:t.string()}),NovelBindingStateSchema=t.object({projectId:t.string(),bindings:t.array(CharacterImageBindingSchema).default([])}),ConfirmedSlotFileSchema=t.object({entries:t.array(ConfirmedSlotEntrySchema).default([])});
